-- Part 1: 创建所有表
CREATE TABLE IF NOT EXISTS todos (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT NOT NULL, description TEXT, status TEXT NOT NULL DEFAULT 'pending', created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000), updated_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS sessions (id TEXT PRIMARY KEY, visiter_id TEXT NOT NULL, visitor_name TEXT NOT NULL, business_id INTEGER NOT NULL DEFAULT 1, service_id INTEGER DEFAULT 0, assigned_staff_id INTEGER, groupid INTEGER DEFAULT 0, status TEXT NOT NULL DEFAULT 'active', state TEXT NOT NULL DEFAULT 'normal', last_message_at INTEGER, unread_by_visitor INTEGER DEFAULT 0, unread_by_staff INTEGER DEFAULT 0, topic TEXT, task_status TEXT NOT NULL DEFAULT 'requirement_discussion', task_status_updated_at INTEGER, queue_position INTEGER, estimated_wait_minutes INTEGER, ip TEXT, from_url TEXT, avatar TEXT, device TEXT, lang TEXT DEFAULT 'cn', transfer_history TEXT, response_time INTEGER, email TEXT, phone TEXT, pid TEXT, params TEXT, referer TEXT, user_agent TEXT, last_visitor_activity_at INTEGER, created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000), updated_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS messages (id INTEGER PRIMARY KEY AUTOINCREMENT, session_id TEXT NOT NULL, sender_type TEXT NOT NULL, content_type TEXT NOT NULL, content TEXT NOT NULL, translated_content TEXT, translate_engine TEXT, translated_at INTEGER, thumbnail_url TEXT, file_name TEXT, file_size INTEGER, is_read INTEGER DEFAULT 0, is_deleted INTEGER DEFAULT 0, deleted_by TEXT, deleted_at INTEGER, product_id INTEGER, product_name TEXT, product_price TEXT, product_image TEXT, product_url TEXT, created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS staff_users (id INTEGER PRIMARY KEY AUTOINCREMENT, business_id INTEGER NOT NULL DEFAULT 0, business_slug TEXT UNIQUE, business_name TEXT, enable_auto_trans INTEGER NOT NULL DEFAULT 0, default_lang TEXT NOT NULL DEFAULT 'zh-CN', username TEXT NOT NULL UNIQUE, password_hash TEXT NOT NULL, email TEXT, name TEXT, role TEXT NOT NULL DEFAULT 'staff', status TEXT NOT NULL DEFAULT 'active', last_active INTEGER, created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000), updated_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS visitors (id INTEGER PRIMARY KEY AUTOINCREMENT, business_id INTEGER NOT NULL DEFAULT 1, visitor_id TEXT NOT NULL, visitor_name TEXT NOT NULL, avatar TEXT, ip TEXT, from_url TEXT, device TEXT, lang TEXT NOT NULL DEFAULT 'cn', status TEXT NOT NULL DEFAULT 'offline', last_visit_at INTEGER, created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS robot_knowledge (id INTEGER PRIMARY KEY AUTOINCREMENT, keyword TEXT NOT NULL, question TEXT NOT NULL, answer TEXT NOT NULL, sort INTEGER NOT NULL DEFAULT 0, status INTEGER NOT NULL DEFAULT 1, lang TEXT NOT NULL DEFAULT 'zh-CN', created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS faq (id INTEGER PRIMARY KEY AUTOINCREMENT, question TEXT NOT NULL, answer TEXT NOT NULL, sort INTEGER NOT NULL DEFAULT 0, status INTEGER NOT NULL DEFAULT 1, lang TEXT NOT NULL DEFAULT 'zh-CN', created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS evaluations (id INTEGER PRIMARY KEY AUTOINCREMENT, session_id TEXT NOT NULL, visitor_name TEXT, score INTEGER NOT NULL DEFAULT 5, comment TEXT, created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS banwords (id INTEGER PRIMARY KEY AUTOINCREMENT, keyword TEXT NOT NULL UNIQUE, level INTEGER NOT NULL DEFAULT 1, replace_with TEXT, status INTEGER NOT NULL DEFAULT 1, created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS visitor_blacklist (id INTEGER PRIMARY KEY AUTOINCREMENT, business_id INTEGER NOT NULL, visitor_id TEXT NOT NULL, ip TEXT, reason TEXT, expires_at INTEGER, created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS chat_stats (id INTEGER PRIMARY KEY AUTOINCREMENT, business_id INTEGER NOT NULL, date TEXT NOT NULL, total_sessions INTEGER DEFAULT 0, active_sessions INTEGER DEFAULT 0, total_messages INTEGER DEFAULT 0, avg_response_time INTEGER DEFAULT 0, satisfaction_rate REAL DEFAULT 0, created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS staff_groups (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL UNIQUE, description TEXT, sort INTEGER NOT NULL DEFAULT 0, status INTEGER NOT NULL DEFAULT 1, created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS staff_group_members (group_id INTEGER NOT NULL, staff_id INTEGER NOT NULL, PRIMARY KEY (group_id, staff_id));
CREATE TABLE IF NOT EXISTS sentences (id INTEGER PRIMARY KEY AUTOINCREMENT, content TEXT NOT NULL, staff_id INTEGER NOT NULL, tag TEXT, state TEXT NOT NULL DEFAULT 'using', lang TEXT NOT NULL DEFAULT 'zh-CN', business_id INTEGER NOT NULL DEFAULT 0, created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS offline_messages (id INTEGER PRIMARY KEY AUTOINCREMENT, visiter_id TEXT, name TEXT NOT NULL, mobile TEXT, email TEXT, content TEXT NOT NULL, business_id INTEGER DEFAULT 0, ip TEXT, from_url TEXT, status TEXT NOT NULL DEFAULT 'pending', created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS queue (id INTEGER PRIMARY KEY AUTOINCREMENT, visiter_id TEXT NOT NULL, service_id INTEGER DEFAULT 0, groupid INTEGER DEFAULT 0, business_id INTEGER DEFAULT 0, state TEXT NOT NULL DEFAULT 'waiting', position INTEGER DEFAULT 0, remind_sent INTEGER DEFAULT 0, evaluation_sent INTEGER DEFAULT 0, created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS evaluation_setting (id INTEGER PRIMARY KEY AUTOINCREMENT, business_id INTEGER DEFAULT 0, title TEXT NOT NULL DEFAULT '满意度评价', questions TEXT NOT NULL DEFAULT '[]', word_switch TEXT NOT NULL DEFAULT 'close', word_title TEXT NOT NULL DEFAULT '', status TEXT NOT NULL DEFAULT 'open', created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000), updated_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS admin_users (id INTEGER PRIMARY KEY AUTOINCREMENT, username TEXT NOT NULL UNIQUE, password_hash TEXT NOT NULL, email TEXT, name TEXT, status TEXT NOT NULL DEFAULT 'active', created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000), updated_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS admin_config (id INTEGER PRIMARY KEY AUTOINCREMENT, key TEXT NOT NULL UNIQUE, value TEXT NOT NULL, description TEXT, created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000), updated_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS roles (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL UNIQUE, description TEXT, permissions TEXT NOT NULL DEFAULT '[]', is_system INTEGER NOT NULL DEFAULT 0, status TEXT NOT NULL DEFAULT 'active', created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000), updated_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS transfer_requests (id INTEGER PRIMARY KEY AUTOINCREMENT, session_id TEXT NOT NULL, from_staff_id INTEGER NOT NULL, to_staff_id INTEGER NOT NULL, reason TEXT, status TEXT NOT NULL DEFAULT 'pending', reject_reason TEXT, created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000), updated_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS visitor_custom_fields (id INTEGER PRIMARY KEY AUTOINCREMENT, business_id INTEGER NOT NULL DEFAULT 0, field_key TEXT NOT NULL, label TEXT NOT NULL, type TEXT NOT NULL DEFAULT 'text', remark TEXT, sort_order INTEGER NOT NULL DEFAULT 0, is_active INTEGER NOT NULL DEFAULT 1, created_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000), updated_at INTEGER NOT NULL DEFAULT (unixepoch() * 1000));
CREATE TABLE IF NOT EXISTS business_domains (id INTEGER PRIMARY KEY AUTOINCREMENT, business_id INTEGER NOT NULL, staff_user_id INTEGER NOT NULL, domain_type TEXT NOT NULL DEFAULT 'auto_subdomain', domain TEXT NOT NULL UNIQUE, subdomain TEXT, domain_platform TEXT DEFAULT 'cloudflare', cf_zone_id TEXT, cf_zone_name TEXT, cf_account_id TEXT, cf_api_token_encrypted TEXT, cf_dns_record_id TEXT, cf_worker_route_id TEXT, verification_status TEXT DEFAULT 'pending', ssl_status TEXT DEFAULT 'pending', is_primary INTEGER DEFAULT 0, status TEXT DEFAULT 'active', error_message TEXT, verified_at INTEGER, created_at INTEGER DEFAULT (unixepoch()), updated_at INTEGER DEFAULT (unixepoch()), FOREIGN KEY (business_id) REFERENCES staff_users(id), FOREIGN KEY (staff_user_id) REFERENCES staff_users(id));
CREATE TABLE IF NOT EXISTS business_ai_config (id INTEGER PRIMARY KEY AUTOINCREMENT, business_id INTEGER NOT NULL UNIQUE, ai_mode TEXT DEFAULT 'platform', cf_account_id TEXT, cf_ai_token_encrypted TEXT, ai_gateway_url TEXT, monthly_translate_count INTEGER DEFAULT 0, monthly_translate_limit INTEGER DEFAULT 10000, total_translate_count INTEGER DEFAULT 0, reset_day INTEGER DEFAULT 1, status TEXT DEFAULT 'active', created_at INTEGER DEFAULT (unixepoch()), updated_at INTEGER DEFAULT (unixepoch()), FOREIGN KEY (business_id) REFERENCES staff_users(id));
CREATE TABLE IF NOT EXISTS domain_operation_logs (id INTEGER PRIMARY KEY AUTOINCREMENT, business_id INTEGER NOT NULL, domain_id INTEGER, operation TEXT NOT NULL, details TEXT, status TEXT DEFAULT 'success', ip_address TEXT, created_at INTEGER DEFAULT (unixepoch()));
